import { useEffect, useState } from "react";
import { Link, useParams, useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { ArrowLeft } from "lucide-react";
import Countdown from "@/components/Countdown";
import Waitlist from "@/components/Waitlist";
import Footer from "@/components/Footer";
import { COLLECTION_BY_SLUG, COLLECTIONS } from "@/lib/collections";
import { fetchLaunchInfo } from "@/lib/api";

export default function CollectionPreview() {
    const { slug } = useParams();
    const navigate = useNavigate();
    const c = COLLECTION_BY_SLUG[slug] || COLLECTIONS[0];
    const [launchDate, setLaunchDate] = useState(null);
    const [waitlistOpen, setWaitlistOpen] = useState(false);

    useEffect(() => {
        fetchLaunchInfo().then((d) => setLaunchDate(d.launch_date)).catch(() => {});
        window.scrollTo({ top: 0, behavior: "instant" });
    }, [slug]);

    return (
        <main data-testid="collection-preview-page" className="relative bg-ivory text-espresso min-h-screen overflow-x-hidden">
            {/* Blurred ethnic backdrop */}
            <div className="absolute inset-0 z-0">
                <img
                    src={c.image}
                    alt={c.name}
                    className="w-full h-full object-cover scale-110"
                    style={{ filter: "blur(28px) saturate(115%)" }}
                />
                <div className="absolute inset-0 bg-ivory/55" />
                <div className="absolute inset-0 bg-gradient-to-b from-ivory/20 via-ivory/40 to-ivory" />
            </div>

            <div className="relative z-10">
                {/* Top bar */}
                <div className="px-6 md:px-12 lg:px-20 pt-7 flex items-center justify-between">
                    <Link to="/" data-testid="preview-nav-logo" className="font-serif text-xl md:text-2xl tracking-tight text-espresso">
                        ShopLive<span className="italic text-maroon">Bharat</span>
                    </Link>
                    <button
                        onClick={() => navigate("/")}
                        data-testid="preview-back-home"
                        className="flex items-center gap-2 text-[11px] uppercase tracking-[0.28em] text-espresso/70 hover:text-maroon transition-colors"
                    >
                        <ArrowLeft className="w-4 h-4" strokeWidth={1.4} /> Return home
                    </button>
                </div>

                <section className="px-6 md:px-12 lg:px-20 pt-20 md:pt-28 pb-12 md:pb-20 max-w-6xl mx-auto text-center">
                    <motion.p
                        initial={{ opacity: 0, y: 14 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.9 }}
                        className="text-[11px] uppercase tracking-[0.32em] text-maroon mb-5"
                        data-testid="preview-eyebrow"
                    >
                        Collection · {c.name}
                    </motion.p>

                    <motion.h1
                        initial={{ opacity: 0, y: 24 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 1.05, delay: 0.05 }}
                        data-testid="preview-heading"
                        className="font-serif text-5xl sm:text-6xl md:text-[6.5rem] leading-[1.02] text-espresso tracking-tightest"
                    >
                        This collection will be{" "}
                        <span className="serif-italic">available at launch.</span>
                    </motion.h1>

                    <motion.p
                        initial={{ opacity: 0, y: 18 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 1, delay: 0.18 }}
                        data-testid="preview-tagline"
                        className="serif-italic text-lg md:text-2xl text-stone mt-6"
                    >
                        {c.tagline}
                    </motion.p>

                    <motion.p
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ duration: 1.1, delay: 0.3 }}
                        className="text-sm md:text-base text-stone max-w-xl mx-auto mt-5"
                    >
                        {c.description} Be awaited — exclusive styles are arriving soon.
                    </motion.p>
                </section>

                <Countdown launchDate={launchDate} compact eyebrow="Early access will open soon" />

                {/* Floating teaser images */}
                <div className="px-6 md:px-12 lg:px-20 mt-12 mb-8 max-w-6xl mx-auto">
                    <div className="grid grid-cols-3 gap-3 md:gap-6">
                        {COLLECTIONS
                            .filter((x) => x.slug !== c.slug)
                            .slice(0, 3)
                            .map((x, i) => (
                                <motion.div
                                    key={x.slug}
                                    initial={{ opacity: 0, y: 24 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    transition={{ duration: 0.9, delay: 0.4 + i * 0.07 }}
                                    className="relative overflow-hidden rounded-2xl md:rounded-[1.6rem] aspect-[3/4]"
                                >
                                    <img src={x.image} alt={x.name} className="absolute inset-0 w-full h-full object-cover" />
                                    <div className="absolute inset-0 bg-gradient-to-t from-espresso/70 via-transparent to-transparent" />
                                    <Link
                                        to={`/collection/${x.slug}`}
                                        data-testid={`preview-related-${x.slug}`}
                                        className="absolute inset-0 z-10"
                                        aria-label={x.name}
                                    />
                                    <div className="absolute bottom-3 left-3 md:bottom-5 md:left-5 text-ivory">
                                        <p className="text-[9px] md:text-[10px] uppercase tracking-[0.28em] opacity-80">Awaiting</p>
                                        <p className="font-serif text-base md:text-2xl leading-tight">{x.name}</p>
                                    </div>
                                </motion.div>
                            ))}
                    </div>
                </div>

                <section className="px-6 md:px-12 lg:px-20 pt-8 pb-24 text-center">
                    <div className="flex flex-wrap justify-center gap-4">
                        <button
                            type="button"
                            onClick={() => setWaitlistOpen(true)}
                            data-testid="preview-cta-waitlist"
                            className="btn-pill btn-primary"
                        >
                            Join the waitlist
                        </button>
                        <Link to="/" data-testid="preview-cta-home" className="btn-pill btn-ghost">
                            Return home
                        </Link>
                    </div>
                    <p className="text-[11px] uppercase tracking-[0.3em] text-maroon mt-10">
                        Launching soon worldwide ✦ Be awaited
                    </p>
                </section>
            </div>

            <Footer />

            <Waitlist open={waitlistOpen} onOpenChange={setWaitlistOpen} />
        </main>
    );
}
